#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, S; scanf("%lld %lld", &N, &S);
        long long ans = (S <= N) ? S : (2LL * N - S);
        printf("%lld\n", ans);
    }
    return 0;
}

